import{_ as o,o as t,c as a,a2 as c}from"./chunks/framework.4hJCcvDE.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"blog/框架设计_003-NPC记忆系统设计.md","filePath":"blog/框架设计_003-NPC记忆系统设计.md","lastUpdated":1784835052000}'),r={name:"blog/框架设计_003-NPC记忆系统设计.md"};function l(i,e,d,n,s,u){return t(),a("div",null,[...e[0]||(e[0]=[c('<h2 id="引言" tabindex="-1">引言 <a class="header-anchor" href="#引言" aria-label="Permalink to &quot;引言&quot;">​</a></h2><p>在做《归义军传说》（火焰纹章式 SRPG）的时候，想加一个特色功能：让 NPC 根据玩家之前的战场行为和剧情选择做出不同反应。简单来说就是让 NPC &quot;记住&quot; 玩家是个什么样的指挥官——激进莽夫还是谨慎策略家，进而影响后续章节的对话、商店价格甚至敌人配置。</p><p>这个系统的核心可以拆成三层：行为追踪层（监听事件 → 翻译为标签）、记忆存储层（标签权重持久化）、以及决策消费层（NPC 读取标签做反应）。目前前两层已经实装，第三层留了接口待接入。</p><h2 id="一、行为追踪层-battlebehaviortracker" tabindex="-1">一、行为追踪层：BattleBehaviorTracker <a class="header-anchor" href="#一、行为追踪层-battlebehaviortracker" aria-label="Permalink to &quot;一、行为追踪层：BattleBehaviorTracker&quot;">​</a></h2><p>这层的工作是订阅战斗事件总线，把玩家的每一次战场操作翻译成带权重的偏好标签。挂在场景里，Start 时订阅 GameEventBus，OnDestroy 时取消订阅。</p><p>代码很简单，就是一堆事件回调：</p><ul><li>玩家造成伤害 → <code>aggressive_attack</code>（侵略性），权重 0.3</li><li>玩家待机不攻击 → <code>cautious_wait</code>（谨慎），权重 0.3</li><li>移动后进入敌人射程 → <code>risky_move</code>（冒险），权重 0.3</li><li>移动后贴近残血友军 → <code>protect_ally</code>（忠诚），权重 0.3</li><li>友军阵亡 → <code>sacrificial_rush</code>（牺牲倾向），权重 0.4（立即落盘防止退出丢数据）</li></ul><p>每个事件只记 0.3~0.4 的权重，意味着玩家打一场战斗（假设平均出手 20 次），某项标签的权重会累积到 6~8。这样设计的好处是<strong>单次行为不决定标签，整体倾向才决定</strong>——偶尔莽一次不会让 NPC 把你当莽夫，但整场都在莽就会。</p><p>追踪器本身不关心 NPC 怎么用这些标签，它只管&quot;忠实记录&quot;。这是有意拆开的：行为追踪和决策消费解耦，以后即使换了消费端的逻辑（比如从标签驱动改为机器学习特征输入），追踪器也不用改。</p><h2 id="二、记忆存储层-npcmemory" tabindex="-1">二、记忆存储层：NPCMemory <a class="header-anchor" href="#二、记忆存储层-npcmemory" aria-label="Permalink to &quot;二、记忆存储层：NPCMemory&quot;">​</a></h2><p>NPCMemory 是一个跨场景的单例（<code>DontDestroyOnLoad</code>），用 JSON 序列化到 <code>Application.persistentDataPath/PlayerMemory/</code>。核心数据结构是 <code>PlayerPreference</code>，内部维护一个 <code>Dictionary&lt;string, float&gt;</code> 存标签权重。</p><p>几个设计点：</p><ol><li><p><strong>分章节记录</strong>：<code>RecordEvent(tag, weight, chapterId)</code> 带上章节 ID，虽然目前权重是全局累加的，但数据结构预留了按章节聚合的空间。以后可以做&quot;第一章 NPC 觉得你很谨慎，第二章开局时他仍然记得&quot;。</p></li><li><p><strong>关键时刻立即落盘</strong>：正常情况下在 <code>OnApplicationQuit</code> 时 Save。但友军阵亡这个事件会立即调 <code>SaveMemory()</code>——因为玩家可能在角色死后直接关游戏，不等到正常退出。</p></li><li><p><strong>剧情选择也进记忆</strong>：<code>RecordStoryChoice(choiceId, alignment)</code>，alignment &gt; 0.5 记 <code>benevolent</code>（仁慈），&lt; -0.5 记 <code>ruthless</code>（冷酷）。这让 NPC 不仅根据战斗风格、也根据剧情中的道德选择来做反应。</p></li><li><p><strong>主导标签查询</strong>：<code>GetDominantTag()</code> 遍历所有权重，返回当前最高的一项。虽然目前消费端还没接入，但这个接口已经给 NPC 对话系统留好了——&quot;你每次战斗都身先士卒&quot;（aggressive）vs &quot;你对部下很严厉&quot;（牺牲倾向高）。</p></li></ol><h2 id="三、消费层的思路-待实现" tabindex="-1">三、消费层的思路（待实现） <a class="header-anchor" href="#三、消费层的思路-待实现" aria-label="Permalink to &quot;三、消费层的思路（待实现）&quot;">​</a></h2><p>有了标签和权重，NPC 的决策树可以这样接入：</p><ul><li>商店老板：<code>aggressive</code> 标签高 → 多进货攻击性武器、提高价格（他知道你需要）；<code>loyal</code> 标签高 → 打折出售伤药、支援道具</li><li>敌人 AI：<code>risk_taker</code> 标签高 → 多布置伏击单位（知道你容易突进）；<code>cautious</code> 标签高 → 加回合限制给你时间压力</li><li>队友对话文本：根据主导标签选择不同的对话分支，比如同样是夸你，&quot;aggressive&quot;对应&quot;将军身先士卒&quot;，&quot;loyal&quot;对应&quot;你从不丢下战友&quot;</li></ul><p>这种设计在商业 SRPG 里其实不常见——大多数 SRPG 的分支只看选择不看行为。让 AI 观察玩家<strong>怎么玩</strong>而非<strong>怎么选</strong>，算是个有点意思的差异化设计。</p><h2 id="四、踩过的坑" tabindex="-1">四、踩过的坑 <a class="header-anchor" href="#四、踩过的坑" aria-label="Permalink to &quot;四、踩过的坑&quot;">​</a></h2><ol><li><p><strong>事件注册时机</strong>：最开始把 <code>TrySubscribe()</code> 写在 <code>Awake</code> 里，发现 <code>GameEventBus.Instance</code> 为 null。原因是 <code>SceneSetup</code> 也是在 <code>Awake</code> 创建 GameEventBus，Unity 的 Awake 调用顺序不确定。改到 <code>Start</code> 里就解决了，因为 Start 在所有 Awake 之后执行。</p></li><li><p><strong>阵亡立即落盘</strong>：测试的时候发现玩家角色阵亡后直接 Alt+F4，记忆文件没有更新。加了一行 <code>NPCMemory.Instance?.SaveMemory()</code> 在 <code>HandleUnitDeath</code> 里就解决了。类似的问题以后加存档系统的时候也要注意——关键时刻手动落盘比依赖 <code>OnApplicationQuit</code> 可靠。</p></li><li><p><strong>单例的 OnDestroy</strong>：<code>NPCMemory</code> 用 <code>DontDestroyOnLoad</code> 跨场景，但场景切换时如果新场景也有一个 <code>NPCMemory</code> GameObject，会触发旧的 <code>OnDestroy</code> 把 <code>Instance</code> 设为 null。标准做法是在 <code>Awake</code> 里做 Instance 检查时，如果发现已有单例直接 <code>Destroy(gameObject)</code>，在自己的 <code>OnDestroy</code> 里只在自己是 Instance 时才置 null。这关已经过了。</p></li></ol><h2 id="参考文献" tabindex="-1">参考文献 <a class="header-anchor" href="#参考文献" aria-label="Permalink to &quot;参考文献&quot;">​</a></h2><ul><li><a href="https://github.com/luoxixuan/srpg-ai-unity-minigame" target="_blank" rel="noreferrer">GitHub — 归义军传说 SRPG</a>（个人项目，本文相关内容来自此仓库）</li><li>本项目设计文档 [Docs/fire-emblem-mechanics.md]（NPC 记忆系统设计）</li></ul>',21)])])}const g=o(r,[["render",l]]);export{h as __pageData,g as default};
